parameters.jsCode:
let intel;
try { intel = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { intel = {}; }
return [{ json: { generated_at: new Date().toISOString(), signals_count: $('Load Pricing Signals').all().length, ...intel } }];

